import React, { useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { InvoiceLineDto } from '../../../services/bh/models';
import { DocumentFormHeader } from '../../../components/layout';
import { InvoiceLinesGrid, useMaterialLinesSelection } from '../../../components/form';
import { CustomerSearchField } from '../../../components/search';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../../../utils/customerField';
import { emptyInvoiceLine, invoiceLinesTotal, normalizeInvoiceLines } from '../../../utils/orderLines';
import df from '../../../styles/documentForm.module.css';

const HoaDonFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [taxCode, setTaxCode] = useState('');
  const [description, setDescription] = useState('');
  const [lines, setLines] = useState<InvoiceLineDto[]>([emptyInvoiceLine()]);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  const customerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );
  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(lines, setLines);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getInvoice(id)
        .then(async inv => {
          if (cancelled) return;
          setInvoiceDate(inv.invoiceDate.slice(0, 10));
          setCustomerId(inv.customerId);
          setDescription('');
          setLines(
            inv.lines?.length
              ? inv.lines.map(l => ({
                  id: l.id,
                  materialCode: l.materialCode,
                  unitCode: l.unitCode,
                  quantity: l.quantity,
                  unitPrice: l.unitPrice,
                  amount: l.amount,
                  taxRate: l.taxRate,
                  taxAmount: l.taxAmount,
                }))
              : [emptyInvoiceLine()],
          );
          const display = await loadCustomerDisplay(inv.customerId, inv.customerName);
          if (!cancelled) {
            setCustomerCode(display.code);
            setCustomerName(display.name);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải hóa đơn'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const addLine = () => {
    setLines(prev => [...prev, emptyInvoiceLine()]);
    setSelectedLineIndex(lines.length);
  };

  const removeLine = (idx: number) => {
    setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyInvoiceLine()];
    });
    setSelectedLineIndex(Math.max(0, idx - 1));
  };

  const handleSave = async () => {
    if (!customerId) {
      dispatchAppToast(dispatch, { message: 'Chọn khách hàng', type: 'error' });
      return;
    }
    const normalized = normalizeInvoiceLines(lines);
    if (normalized.length === 0) {
      dispatchAppToast(dispatch, { message: 'Thêm ít nhất một dòng hàng', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (isEdit && id) {
        await bhService.updateInvoice(id, { taxCode, description, lines: normalized });
        dispatchAppToast(dispatch, { message: 'Cập nhật hóa đơn thành công', type: 'success' });
      } else {
        await bhService.createInvoice({ invoiceDate, customerId, taxCode, description, lines: normalized });
        dispatchAppToast(dispatch, { message: 'Tạo hóa đơn thành công', type: 'success' });
      }
      navigate('/bh/hoa-don');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  const totals = invoiceLinesTotal(lines);

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/bh/hoa-don')}
        title={isNew ? 'Tạo hóa đơn' : 'Sửa hóa đơn'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo hóa đơn"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin hóa đơn</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Ngày hóa đơn</label>
            <Input type="date" value={invoiceDate} onChange={e => setInvoiceDate(e.target.value)} disabled={isEdit} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Khách hàng</label>
            <CustomerSearchField
              customerId={customerId}
              customerCode={customerCode}
              customerName={customerName}
              onSelect={customerHandlers.onSelect}
              onClear={customerHandlers.onClear}
              disabled={isEdit}
              testIdPrefix="hoa-don-customer"
            />
          </div>
          <div className={df.field}>
            <label className={df.label}>Mã số thuế</label>
            <Input value={taxCode} onChange={e => setTaxCode(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Diễn giải</label>
            <Input value={description} onChange={e => setDescription(e.target.value)} />
          </div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết hàng hóa</h2>
        <InvoiceLinesGrid
          lines={lines}
          canEdit
          onChange={setLines}
          onAddLine={addLine}
          onCopyLine={copyLine}
          lineRowProps={lineRowProps}
          onRemoveLine={removeLine}
        />
      </div>
      <div className={df.footer}>
        <div className={df.totalBlock}>
          <span className={df.totalLabel}>Tạm tính:</span>
          <span className={df.totalValue}>{totals.subTotal.toLocaleString('vi-VN')}</span>
        </div>
        <div className={df.totalBlock}>
          <span className={df.totalLabel}>Thuế:</span>
          <span className={df.totalValue}>{totals.taxAmount.toLocaleString('vi-VN')}</span>
        </div>
        <div className={df.totalBlock}>
          <span className={df.totalLabel}>Tổng cộng:</span>
          <span className={df.totalValue}>{totals.total.toLocaleString('vi-VN')}</span>
        </div>
      </div>
    </div>
  );
};

export default HoaDonFormPage;
